#include<bits/stdc++.h>
using namespace std;
vector<long long> a[500005][2];
long long n,dp[500005][2],s;
bool v[500005];
void qian(int x){
    v[x]=1;
    for(int i=0;i<a[x][0].size();i++){
           if(!v[a[x][0][i]]) qian(a[x][0][i]);
    }
    long long ans=0;
    long long maxx=0;
    for(int i=0;i<a[x][0].size();i++){
       if(!v[a[x][0][i]]) maxx=max(maxx,dp[a[x][0][i]][1]+a[x][1][i]);
    }
    dp[x][1]=maxx;
    for(int i=0;i<a[x][0].size();i++){
        if(!v[a[x][0][i]]) ans+=(maxx-(dp[a[x][0][i]][1]+a[x][1][i]));
        if(!v[a[x][0][i]]) ans+=dp[a[x][0][i]][0];
    }
    dp[x][0]=ans;
    v[x]=0;
    return;

}
int main(){
    cin>>n>>s;
    for(int i=0;i<n-1;i++){
        int x,y,z;
        cin>>x>>y>>z;
        a[x][0].push_back(y);
        a[x][1].push_back(z);
        a[y][0].push_back(x);
        a[y][1].push_back(z);
    }
    qian(s);
    cout<<dp[s][0];
    return 0;
}
